// Lookup map for fast image URL retrieval by (knifeDefindex, paintId)
const _knifeSkinImageMap: Map<string, string> = new Map();
for (const [key, skins] of Object.entries(knifeSkinsByType)) {
  for (const skin of skins) {
    _knifeSkinImageMap.set(`${key}-${skin.id}`, skin.image);
  }
}

export function getKnifeSkinImageUrl(knifeDefindex: number, paintId: number): string | undefined {
  return _knifeSkinImageMap.get(`${knifeDefindex}-${paintId}`);
}
